'use client';

import React, { useMemo, useState } from 'react';
import { 
  Trash2, 
  Search, 
  Loader2, 
  Eye,
  AlertTriangle,
} from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { useCollection, useFirestore, useMemoFirebase } from '@/firebase';
import { collection, doc, deleteDoc } from 'firebase/firestore';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { 
  Table, 
  TableBody, 
  TableCell, 
  TableHead, 
  TableHeader, 
  TableRow 
} from '@/components/ui/table';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { 
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import { useToast } from '@/hooks/use-toast';
import { countries } from '@/lib/countries';
import { format } from 'date-fns';

/**
 * @fileOverview Refined User account management with specifically styled action buttons.
 */
export default function AdminUsersPage() {
  const firestore = useFirestore();
  const { toast } = useToast();
  
  // UI State for inputs
  const [searchTerm, setSearchTerm] = useState('');
  const [countryFilter, setCountryFilter] = useState('all');
  const [currencyFilter, setCurrencyFilter] = useState('all');
  const [warningFilter, setWarningFilter] = useState('all');

  // Applied filter state (updated only on "Filter" button click)
  const [appliedFilters, setAppliedFilters] = useState({
    search: '',
    country: 'all',
    currency: 'all',
    warning: 'all'
  });

  const usersQuery = useMemoFirebase(() => {
    if (!firestore) return null;
    return collection(firestore, 'users');
  }, [firestore]);

  const { data: users, isLoading } = useCollection(usersQuery);

  // Derived data for dropdowns
  const registeredUsers = useMemo(() => {
    if (!users) return [];
    return users.filter(u => u.email && u.email.includes('@'));
  }, [users]);

  const uniqueCountries = useMemo(() => {
    const codes = Array.from(new Set(registeredUsers.map(u => u.country || 'IN')));
    return codes.map(code => countries.find(c => c.code === code)).filter(Boolean);
  }, [registeredUsers]);

  const uniqueCurrencies = useMemo(() => {
    const codes = Array.from(new Set(registeredUsers.map(u => u.country || 'IN')));
    const symbols = Array.from(new Set(codes.map(code => {
      const c = countries.find(item => item.code === code);
      return c?.currency.symbol === '₹' ? 'INR' : 'USD';
    })));
    return symbols;
  }, [registeredUsers]);

  const handleApplyFilters = () => {
    setAppliedFilters({
      search: searchTerm,
      country: countryFilter,
      currency: currencyFilter,
      warning: warningFilter
    });
  };

  const filteredUsers = useMemo(() => {
    return registeredUsers.filter(u => {
      const matchesSearch = 
        u.email?.toLowerCase().includes(appliedFilters.search.toLowerCase()) || 
        u.name?.toLowerCase().includes(appliedFilters.search.toLowerCase());
      
      const matchesCountry = appliedFilters.country === 'all' || u.country === appliedFilters.country;
      
      const userCurrency = countries.find(c => c.code === (u.country || 'IN'))?.currency.symbol === '₹' ? 'INR' : 'USD';
      const matchesCurrency = appliedFilters.currency === 'all' || userCurrency === appliedFilters.currency;
      
      // Assume 'warningCount' exists on user or simulate
      const userHasWarning = (u.warningCount || 0) > 0;
      const matchesWarning = 
        appliedFilters.warning === 'all' || 
        (appliedFilters.warning === 'with' && userHasWarning) ||
        (appliedFilters.warning === 'without' && !userHasWarning);

      return matchesSearch && matchesCountry && matchesCurrency && matchesWarning;
    });
  }, [registeredUsers, appliedFilters]);

  const handleDeleteUser = async (userId: string, userEmail: string) => {
    if (!firestore) return;
    try {
      await deleteDoc(doc(firestore, 'users', userId));
      toast({
        title: "User Profile Deleted",
        description: `Successfully removed profile for ${userEmail}.`,
      });
    } catch (error: any) {
      toast({
        variant: "destructive",
        title: "Delete Failed",
        description: error.message,
      });
    }
  };

  if (isLoading) {
    return (
      <div className="flex h-[40vh] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-700">
      
      {/* Header Card */}
      <Card className="shadow-sm border border-slate-100 rounded-2xl overflow-hidden bg-white">
        <CardContent className="p-8">
          <div className="flex items-center justify-between">
            <div className="space-y-1">
              <h1 className="text-3xl font-bold text-[#23414d]">User Account Management</h1>
              <p className="text-sm text-slate-500">Total Registered: {registeredUsers.length} users | Active Filter: {filteredUsers.length} shown</p>
              <div className="flex items-center gap-2 pt-1 text-[13px] font-medium text-cyan-500">
                <span>Account deletions require administrative audit</span>
                <span className="text-slate-300">•</span>
                <span>Real-time profile verification enabled</span>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Filter Bar Card */}
      <Card className="shadow-sm border border-slate-100 rounded-2xl bg-white overflow-hidden">
        <CardContent className="p-8 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-4 lg:grid-cols-5 gap-6 items-end">
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-600">Country</label>
              <Select value={countryFilter} onValueChange={setCountryFilter}>
                <SelectTrigger className="h-11 rounded-lg border-slate-200">
                  <SelectValue placeholder="All Countries" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Countries</SelectItem>
                  {uniqueCountries.map(c => (
                    <SelectItem key={c?.code} value={c?.code || ''}>{c?.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-600">Currency</label>
              <Select value={currencyFilter} onValueChange={setCurrencyFilter}>
                <SelectTrigger className="h-11 rounded-lg border-slate-200">
                  <SelectValue placeholder="All Currencies" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Currencies</SelectItem>
                  {uniqueCurrencies.map(symbol => (
                    <SelectItem key={symbol} value={symbol}>{symbol}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-600">Warnings</label>
              <Select value={warningFilter} onValueChange={setWarningFilter}>
                <SelectTrigger className="h-11 rounded-lg border-slate-200">
                  <SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Users</SelectItem>
                  <SelectItem value="with">With Warnings</SelectItem>
                  <SelectItem value="without">Without Warnings</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2 lg:col-span-1">
              <label className="text-sm font-medium text-slate-600">Search</label>
              <Input 
                placeholder="Name or email..." 
                className="h-11 rounded-lg border-slate-200"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <Button 
              onClick={handleApplyFilters}
              className="h-11 bg-[#1e3a8a] hover:bg-[#1e3a8a]/90 text-white rounded-lg px-8 font-bold flex items-center justify-center gap-2"
            >
              <Search className="w-4 h-4" />
              Filter
            </Button>
          </div>

          {/* User Table */}
          <div className="rounded-lg border border-slate-100 overflow-hidden">
            <Table>
              <TableHeader className="bg-[#f1f5f9]">
                <TableRow className="hover:bg-transparent border-0">
                  <TableHead className="w-16 font-bold text-[#1e3a8a]">ID</TableHead>
                  <TableHead className="font-bold text-[#1e3a8a]">Username</TableHead>
                  <TableHead className="font-bold text-[#1e3a8a]">Email</TableHead>
                  <TableHead className="font-bold text-[#1e3a8a]">Country</TableHead>
                  <TableHead className="font-bold text-[#1e3a8a]">Currency</TableHead>
                  <TableHead className="font-bold text-[#1e3a8a]">Joined</TableHead>
                  <TableHead className="font-bold text-[#1e3a8a]">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredUsers.length > 0 ? (
                  filteredUsers.map((user, index) => {
                    const country = countries.find(c => c.code === user.country);
                    const joinedDate = new Date(); // Mocking joined date if not in schema
                    return (
                      <TableRow key={user.id} className="hover:bg-slate-50 border-b border-slate-50 last:border-0">
                        <TableCell className="text-slate-600 font-medium">{1000 + index}</TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <span className="font-medium text-slate-700">{user.name || 'Anonymous'}</span>
                            {(user.warningCount || 0) > 0 && (
                              <Badge className="bg-red-500 hover:bg-red-500 text-white text-[9px] h-4 rounded px-1.5 font-bold">WARNED</Badge>
                            )}
                          </div>
                        </TableCell>
                        <TableCell className="text-slate-600">{user.email}</TableCell>
                        <TableCell className="text-slate-600 font-medium">{user.country || 'IN'}</TableCell>
                        <TableCell className="text-slate-600 font-medium">
                          {country?.currency.symbol === '₹' ? 'INR' : 'USD'}
                        </TableCell>
                        <TableCell className="text-slate-600 text-sm">
                          <div>{format(joinedDate, 'MMM dd, yyyy')}</div>
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            {/* Eye button: View Info */}
                            <Button 
                              variant="ghost" 
                              size="icon" 
                              className="h-9 w-9 bg-[#23414d] hover:bg-[#23414d]/90 text-white rounded-lg flex items-center justify-center"
                              title="View Information"
                            >
                              <Eye className="w-4 h-4" />
                            </Button>

                            {/* Warning sign button: Send/View Warnings */}
                            <Button 
                              variant="ghost" 
                              size="icon" 
                              className="h-9 w-9 bg-[#f59e0b] hover:bg-[#f59e0b]/90 text-white rounded-lg flex items-center justify-center"
                              title={`Warnings Sent: ${user.warningCount || 0}`}
                            >
                              <AlertTriangle className="w-4 h-4" />
                            </Button>

                            {/* Delete button: Remove account */}
                            <AlertDialog>
                              <AlertDialogTrigger asChild>
                                <Button 
                                  variant="ghost" 
                                  size="icon" 
                                  className="h-9 w-9 bg-[#dc2626] hover:bg-[#dc2626]/90 text-white rounded-lg flex items-center justify-center"
                                  title="Delete Account"
                                >
                                  <Trash2 className="w-4 h-4" />
                                </Button>
                              </AlertDialogTrigger>
                              <AlertDialogContent className="rounded-3xl border-0 shadow-2xl p-8 bg-white">
                                <AlertDialogHeader>
                                  <AlertDialogTitle className="text-2xl font-bold text-[#1e293b]">Confirm Deletion</AlertDialogTitle>
                                  <AlertDialogDescription className="text-slate-500 font-medium pt-2">
                                    Are you sure you want to delete the profile for <span className="font-bold text-slate-700">{user.email}</span>? This action is irreversible and will block future logins.
                                  </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter className="mt-8 gap-3">
                                  <AlertDialogCancel className="rounded-xl border-slate-200 h-11 px-6 font-bold">Cancel</AlertDialogCancel>
                                  <AlertDialogAction 
                                    onClick={() => handleDeleteUser(user.id, user.email)}
                                    className="rounded-xl bg-red-500 hover:bg-red-600 text-white h-11 px-8 font-bold"
                                  >
                                    Confirm Delete
                                  </AlertDialogAction>
                                </AlertDialogFooter>
                              </AlertDialogContent>
                            </AlertDialog>
                          </div>
                        </TableCell>
                      </TableRow>
                    );
                  })
                ) : (
                  <TableRow>
                    <TableCell colSpan={7} className="h-48 text-center text-slate-400 font-medium">
                      No matching registered users found.
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}
